import{_ as a,c as s,a as i,o as n}from"./app-CEcM0piI.js";const t={};function d(l,e){return n(),s("div",null,e[0]||(e[0]=[i(`<p>视口（viewport）就是浏览器显示页面内容的屏幕区域。视口可以分为布局视口、视觉视口和理想视口</p><h3 id="布局视口layout-viewport" tabindex="-1"><a class="header-anchor" href="#布局视口layout-viewport"><span>布局视口layout viewport</span></a></h3><p>般移动设备的浏览器都默认设置了一个布局视口，用于解决早期的PC端页面在手机上显示的问题。iOS,Android基本都将这个视口分辨率设置为980px，所以PC上的网页大多都能在手机上呈现，只不过元素看上去很小，一般默认可以通过手动缩放网页。</p><h3 id="视觉视口visualviewport" tabindex="-1"><a class="header-anchor" href="#视觉视口visualviewport"><span>视觉视口visualviewport</span></a></h3><p>字面意思，它是用户正在看到的网站的区域。。注意：是网站的区域。我们可以通过缩放去操作视觉视口，但不会影响布局视口，布局视口仍保持原来的宽度。</p><h3 id="理想视口idealiviewport" tabindex="-1"><a class="header-anchor" href="#理想视口idealiviewport"><span>理想视口idealIviewport</span></a></h3><p>为了使网站在移动端有最理想的浏览和阅读宽度而设定理想视口，对设备来讲，是最理想的视口尺寸需要手动添写meta视口标签通知浏览器操作meta视口标签的主要目的：布局视口的宽度应该与理想视口的宽度一致，简单理解就是设备有多宽，我们布局的视口就多宽</p><h2 id="meta视口标签" tabindex="-1"><a class="header-anchor" href="#meta视口标签"><span>meta视口标签</span></a></h2><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;meta name=&quot;viewport&quot; content=&quot;width=device-width, user-scalable=no,initial-scale=1.0,, maximum-scale=1.0, minimum-scale=1.0&quot;&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><table><thead><tr><th>属性</th><th>解释说明</th></tr></thead><tbody><tr><td>width</td><td>宽度设置的是viewport宽度，可以设置device-width特殊值</td></tr><tr><td>initial-scale</td><td>初始缩放比，大于0的数字</td></tr><tr><td>maximum-scale</td><td>最大缩放比，大于0的数字</td></tr><tr><td>minimum-scale</td><td>最小缩放比，大于0的数字</td></tr><tr><td>user-scalable</td><td>用户是否可以缩放，yes或no（1或0）<br></td></tr></tbody></table><h1 id="二倍图" tabindex="-1"><a class="header-anchor" href="#二倍图"><span>二倍图</span></a></h1><h2 id="物理像素-物理像素比" tabindex="-1"><a class="header-anchor" href="#物理像素-物理像素比"><span>物理像素&amp;物理像素比</span></a></h2><p>物理像素点指的是屏幕显示的最小颗粒，是物理真实存在的。这是厂商在出厂时就设置好了,比如苹果6\\7\\8是750*1334 我们开发时候的1px不是一定等于1个物理像素的 PC端页面，1个px等于1个物理像素的，但是移动端就不尽相同 一个px的能显示的物理像素点的个数，称为物理像素比或屏幕像素比</p><p>Retina（视网膜屏幕）是一种显示技术，可以将把更多的物理像素点压缩至一块屏幕里从而达到更高的分辨率，并提高屏幕显示的细腻程度。 这样手机上的1px不一定等于1物理像素</p><p>对于一个图片,在手机的Retina屏中打开，按照物理像素比会放大倍数，这样会造成图片模糊</p><p>在标准的viewport设置中，使用倍图来提高图片质量，解决在高清设备中的模糊问题 通常使用二倍图，因为iPhone6\\78的影响，但是现在还存在3倍图4倍图的情况，这个看实际开发公司需求</p><p>准备的图片比实际需要的大两倍然后再手动缩放,这种方式就是二倍图</p><h3 id="背景图片拉伸" tabindex="-1"><a class="header-anchor" href="#背景图片拉伸"><span>背景图片拉伸</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>background-size:50%;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><table><thead><tr><th>属性</th><th>作用</th></tr></thead><tbody><tr><td>cover</td><td>缩放背景图,使其能够完全覆盖盒子,可能会超出</td></tr><tr><td>contain</td><td>等比例缩放,直到一个边完全覆盖,可能覆盖不完全</td></tr></tbody></table><h1 id="移动端开发选择" tabindex="-1"><a class="header-anchor" href="#移动端开发选择"><span>移动端开发选择</span></a></h1><h2 id="单独移动端页面-主流" tabindex="-1"><a class="header-anchor" href="#单独移动端页面-主流"><span>单独移动端页面(主流)</span></a></h2><p>通常情况下，网址域名前面加m(mobile)可以打开移动端。通过判断设备，如果是移动设备打开，则跳到移动端页面。</p><p>如: 京东官网 : https://www.jd.com/ 使用移动端打开就会跳转 : https://m.jd.com/</p><h2 id="响应式兼容pc移动端" tabindex="-1"><a class="header-anchor" href="#响应式兼容pc移动端"><span>响应式兼容PC移动端</span></a></h2><p>通过判断屏幕宽度来改变样式，以适应不同终端。</p><p>如: 三星电子官网：www.samsung.com/cn/</p><p>缺点：制作麻烦，需要花很大精力去调兼容性问题</p><h2 id="技术解决方案" tabindex="-1"><a class="header-anchor" href="#技术解决方案"><span>技术解决方案</span></a></h2><p>移动端浏览器基本以webkit内核为主，因此我们就考虑webkit谦容性问题。</p><h3 id="css初始化normalize-css" tabindex="-1"><a class="header-anchor" href="#css初始化normalize-css"><span>CSS初始化normalize.css</span></a></h3><p>移动端CSS初始化推荐使用normalize.css/</p><ol><li>保护了有价值的默认值</li><li>修复了浏览器的bug</li><li>是模块化的</li><li>拥有详细的文档</li></ol><h3 id="特殊样式" tabindex="-1"><a class="header-anchor" href="#特殊样式"><span>特殊样式</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>/*CSS3盒子模型*/</span></span>
<span class="line"><span>box-sizing: border-box;</span></span>
<span class="line"><span>-webkit-box-sizing: border-box;</span></span>
<span class="line"><span>/*点击高亮我们需要清除清除 设置为transparent完成透明*/</span></span>
<span class="line"><span>-webkit-tap-highlight-color: transparent;</span></span>
<span class="line"><span>/*在移动端浏览器默认的外观在iOS上加上这个属性才能给按钮和输入框自定义样式*/</span></span>
<span class="line"><span>-webkit-appearance: none;</span></span>
<span class="line"><span>/*禁用长按页面时的弹出菜单*/</span></span>
<span class="line"><span>img,a { -webkit-tquch-callout: none; }</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="常见布局" tabindex="-1"><a class="header-anchor" href="#常见布局"><span>常见布局</span></a></h1><h2 id="流式布局-百分比布局" tabindex="-1"><a class="header-anchor" href="#流式布局-百分比布局"><span>流式布局(百分比布局)</span></a></h2><p>流式布局，就是百分比布局，也称非固定像素布局。 通过盒子的宽度设置成百分比来根据屏幕的宽度来进行伸缩，不受固定像素的限制，内容向两侧填充。 流式布局方式是移动web开发使用的比较常见的布局方式。</p><p><strong>宽度最大值最小值</strong> 通过<code>max-width</code>和<code>min-width</code>属性设置</p><h2 id="flex布局" tabindex="-1"><a class="header-anchor" href="#flex布局"><span>flex布局</span></a></h2><p>flex是display的一种属性,将display设置为flex之后就是flex布局了</p><p>flex是flexibleBox的缩写，意为&quot;弹性布局”，用来为盒状模型提供最大的灵活性，任何一个容器都可以指定为 flex 布局。</p><p>当我们为父盒子设为flex布局以后，子元素的float、clear和vertical-align属性将失效。伸缩布局=弹性布局=伸缩盒布局=弹性盒布局=flex布局</p><p>采用Flex布局的元素，称为Flex容器（flexcontainer），简称&quot;容器&quot;。它的所有子元素自动成为容器成员，称为Flex项目（flexitem），简称&quot;项目&quot;。</p><p><strong>flex布局原理</strong>： 就是通过给父盒子添加flex属性，来控制子盒子的位置和排列方式</p><h3 id="常见父项属性" tabindex="-1"><a class="header-anchor" href="#常见父项属性"><span>常见父项属性</span></a></h3><ul><li>flex-direction：设置主轴的方向</li><li>justify-content：设置主轴上的子元素排列方式</li><li>flex-wrap：设置子元素是否换行</li><li>align-content：设置侧轴上的子元素的排列方式（多行）</li><li>align-items：设置侧轴上的子元素排列方式（单行）</li><li>flex-flow：复合属性，相当于同时设置了flex-direction和flex-wrap</li></ul><h4 id="flex-direction设置主轴的方向" tabindex="-1"><a class="header-anchor" href="#flex-direction设置主轴的方向"><span>flex-direction设置主轴的方向</span></a></h4><p><strong>主轴与侧轴</strong> 在flex布局中，是分为主轴和侧轴两个方向，同样的叫法有：行和列、x轴和y轴</p><p>默认主轴方向就是×轴方向，水平向右 默认侧轴方向就是y轴方向，水平向下</p><p>flex-direction属性决定主轴的方向（即项目的排列方向） 主轴和侧轴是会变化的，就看flex-direction设置谁为主轴，剩下的就是侧轴。而我们的子元素是跟着主轴来排列的</p><table><thead><tr><th>属性值</th><th>说明</th></tr></thead><tbody><tr><td>row</td><td>默认值从左到右</td></tr><tr><td>row-reverse</td><td>从右到左</td></tr><tr><td>column</td><td>从上到下</td></tr><tr><td>column-reverse</td><td>从下到上</td></tr></tbody></table><h4 id="justify-content设置主轴上的子元素排列方式" tabindex="-1"><a class="header-anchor" href="#justify-content设置主轴上的子元素排列方式"><span>justify-content设置主轴上的子元素排列方式</span></a></h4><p>justify-content属性定义了项目在<mark>主轴</mark>上的对齐方式</p><table><thead><tr><th>属性值</th><th>说明</th></tr></thead><tbody><tr><td>flex-start</td><td>默认值从头部开始如果主轴是x轴，左对齐</td></tr><tr><td>flex-end</td><td>右对齐</td></tr><tr><td>center</td><td>在主轴居中对齐（如果主轴是x轴则水平居中）</td></tr><tr><td>space-around</td><td>平分剩余空间</td></tr><tr><td>space-between</td><td>先两边贴边再平分剩余空间（重要）</td></tr></tbody></table><h4 id="flex-wrap设置子元素是否换行" tabindex="-1"><a class="header-anchor" href="#flex-wrap设置子元素是否换行"><span>flex-wrap设置子元素是否换行</span></a></h4><p>默认情况下，项目都排在一条线（又称”轴线”）上。flex-wrap属性定义，flex布局中默认是不换行的。 如果添加的子元素总长度大于父元素的长度就会压缩子元素的长度</p><table><thead><tr><th>属性值</th><th>说明</th></tr></thead><tbody><tr><td>nowrap</td><td>默认值，不换行</td></tr><tr><td>wsap</td><td>换行</td></tr></tbody></table><h4 id="align-items设置侧轴上的子元素排列方式-单行" tabindex="-1"><a class="header-anchor" href="#align-items设置侧轴上的子元素排列方式-单行"><span>align-items设置侧轴上的子元素排列方式（单行)</span></a></h4><p><mark>只适用于单行</mark> 该属性是控制子项在侧轴（默认是y轴）上的排列方式在子项为单项的时候使用</p><table><thead><tr><th>属性值</th><th>说明</th></tr></thead><tbody><tr><td>flex-start</td><td>从上到下</td></tr><tr><td>flex-end</td><td>从下到上</td></tr><tr><td>center</td><td>挤在一起居中（垂直居中）</td></tr><tr><td>stretch</td><td>拉伸（默认值）,子盒子不给大小时就会默认拉伸到侧轴的长度</td></tr></tbody></table><h4 id="align-content设置侧轴上的子元素的排列方式-多行" tabindex="-1"><a class="header-anchor" href="#align-content设置侧轴上的子元素的排列方式-多行"><span>align-content设置侧轴上的子元素的排列方式（多行）</span></a></h4><p>设置子项在侧轴上的排列方式并且只能用于子项出现换行的情况（多行），在单行下是没有效果的。</p><table><thead><tr><th>属性值</th><th>说明</th></tr></thead><tbody><tr><td>flex-start</td><td>默认值在侧轴的头部开始排列</td></tr><tr><td>flex-end</td><td>在侧轴的尾部开始排列</td></tr><tr><td>center</td><td>在侧轴中间显示</td></tr><tr><td>space-around</td><td>子项在侧轴平分剩余空间</td></tr><tr><td>space-between</td><td>子项在侧轴先分布在两头，再平分剩余空间</td></tr><tr><td>stretch</td><td>设置子项元素高度平分父元素高度<br></td></tr></tbody></table><h4 id="flex-flow" tabindex="-1"><a class="header-anchor" href="#flex-flow"><span>flex-flow</span></a></h4><p>flex-flow属性是flex-direction和flex-wrap属性的复合属性</p><h3 id="子项常见属性" tabindex="-1"><a class="header-anchor" href="#子项常见属性"><span>子项常见属性</span></a></h3><ul><li>flex子项目占的份数</li><li>align-self控制子项自己在侧轴的排列方式</li><li>order属性定义子项的排列顺序（前后顺序）</li></ul><h4 id="flex属性" tabindex="-1"><a class="header-anchor" href="#flex属性"><span>flex属性</span></a></h4><p>flex属性定义子项目分配<strong>剩余空间</strong>，用flex来表示占多少份数。 数字值,表示占用的份数</p><h4 id="align-self控制子项自己在侧轴上的排列方式" tabindex="-1"><a class="header-anchor" href="#align-self控制子项自己在侧轴上的排列方式"><span>align-self控制子项自己在侧轴上的排列方式</span></a></h4><p>align-self属性允许单个项目有与其他项目不一样的对齐方式，可覆盖align-items属性。默认值为auto，表示继承父元素的align-items属性，如果没有父元素，则等同于stretch。</p><h4 id="order属性定义项目的排列顺序" tabindex="-1"><a class="header-anchor" href="#order属性定义项目的排列顺序"><span>order属性定义项目的排列顺序</span></a></h4><p>可以为负值 数值越小，排列越靠前，默认为0。</p><h3 id="渐变颜色" tabindex="-1"><a class="header-anchor" href="#渐变颜色"><span>渐变颜色</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>background:linear-gradient(起始方向,颜色1,颜色2...);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>背景渐变必须添加浏览器私有前缀 起始方向可以是：方位名词或者度数，如果省略默认就是top</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>background: -webkit-linear-gradient(left, red , blue);</span></span>
<span class="line"><span>background: -webkit-linear-gradient(left top, red , blue);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="rem布局" tabindex="-1"><a class="header-anchor" href="#rem布局"><span>rem布局</span></a></h2><p>让屏幕发生变化的时候元素高度和宽度等比例缩放 rem（root em)是一个相对单位，类似于em，em是父元素字体大小</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>.father{</span></span>
<span class="line"><span>	font-size : 12px;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>.child{</span></span>
<span class="line"><span>	widget: 10em;</span></span>
<span class="line"><span>	height: 10em;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>孩子的宽高为120px即父元素字体大小的10倍</p><p>rem就是根标签字体大小的倍数(&lt;html&gt;标签的)</p><h3 id="媒体查询" tabindex="-1"><a class="header-anchor" href="#媒体查询"><span>媒体查询</span></a></h3><p>语法:</p><ul><li>用@media开头注意@符号</li><li>mediatype媒体类型</li><li>关键字and not only</li><li>media feature媒体特性必须有小括号包含</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@media mediatype and|not|only(media feature){</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>将不同的终端设备划分成不同的类型，称为媒体类型</p><table><thead><tr><th>值</th><th>说明</th></tr></thead><tbody><tr><td>all</td><td>用于所有设备</td></tr><tr><td>print</td><td>用于打印机和打印预览</td></tr><tr><td>scree</td><td>用于电脑屏幕，平板电脑，智能手机等</td></tr></tbody></table><p>关键字将媒体类型或多个媒体特性连接到一起做为媒体查询的条件。</p><table><thead><tr><th>关键字</th><th>说明</th></tr></thead><tbody><tr><td>and</td><td>可以将多个媒体特性连接到一起，相当于“且”的意思。</td></tr><tr><td>not</td><td>排除某个媒体类型相当于“非”的意思，可以省略。</td></tr><tr><td>only</td><td>指定某个特定的媒体类型，可以省略。</td></tr></tbody></table><p>每种媒体类型都具体各自不同的特性，根据不同媒体类型的媒体特性设置不同的展示风格。我们暂且了解三个。 注意他们要加小括号包含</p><table><thead><tr><th>值</th><th>说明</th></tr></thead><tbody><tr><td>width</td><td>定义输出设备中页面可见区域的宽度</td></tr><tr><td>min-width</td><td>定义输出设备中页面最小可见区域宽度</td></tr><tr><td>max-width</td><td>定义输出设备中页面最大可见区域宽度</td></tr></tbody></table><p>示例:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@media screen and(max-width: 800px) {</span></span>
<span class="line"><span>	body {</span></span>
<span class="line"><span>		background-color:pink;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>当网页在屏幕上宽度小于等于800px时背景颜色为粉色</p><h3 id="引入资源" tabindex="-1"><a class="header-anchor" href="#引入资源"><span>引入资源</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;link rel=&quot;stylesheet&quot; href=&quot;style320.css&quot; media=&quot;screen and (min-width: 320px)&quot;&gt;</span></span>
<span class="line"><span>&lt;link rel=&quot;stylesheet&quot; href=&quot;style640.css&quot; media=&quot;screen and （min-width: 640px)&quot;&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>针对不同的屏幕尺寸引入不同的css样式</p><h1 id="less" tabindex="-1"><a class="header-anchor" href="#less"><span>less</span></a></h1><p>Less（LeanerStyleSheets的缩写）是一门CSS扩展语言，也成为CSS预处理器。 做为CSS的一种形式的扩展，它并没有减少CSS的功能，而是在现有的CSS语法上，为CSS加入程序式语 言的特性。 它在CSS的语法基础之上，引I入了变量，Mixin（混入），运算以及函数等功能，大大简化了CSS的编写并且降低了CSS的维护成本，就像它的名称所说的那样，LeSs可以让我们用更少的代码做更多的事情。</p><p>一句话：Less是一门CSS预处理语言，它扩展了CSS的动态特性。</p><h3 id="定义变量" tabindex="-1"><a class="header-anchor" href="#定义变量"><span>定义变量</span></a></h3><p>使用<code>@变量名:值;</code>的语法定义变量 使用时需要使用@取出变量值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@color:pink;</span></span>
<span class="line"><span>body{</span></span>
<span class="line"><span>	background-color: @color;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="嵌套" tabindex="-1"><a class="header-anchor" href="#嵌套"><span>嵌套</span></a></h3><p>在less中允许嵌套,如:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>div{</span></span>
<span class="line"><span>	a{</span></span>
<span class="line"><span>		</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>相当于css的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>div{</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>div a{</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在嵌套使用时less编译成css语言后会在子元素前面加一个空格,这样会导致只能使用子代选择器,如果在里面写伪类选择器会因为空格的原因:和标签会被隔开 可以在前面加一个&amp;符表示嵌套伪类选择器,伪元素,交集选择器也一样</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>a{</span></span>
<span class="line"><span>	&amp;:hover{</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="算术运算" tabindex="-1"><a class="header-anchor" href="#算术运算"><span>算术运算</span></a></h3><p>在less中可以进行算术运算,运算符的左右两侧必须用空格隔开</p><p>两个数参与运算如果只有一个数有单位,以有单位的那个单位为准 如果两个数都有单位且不同,以第一个元素的单位为准</p><h2 id="vw-vh" tabindex="-1"><a class="header-anchor" href="#vw-vh"><span>vw/vh</span></a></h2><p>相对视口的尺寸计算结果</p><ul><li>vw : viewportwidth 1vw=1/100视口宽度</li><li>vh : viewport height 1vh=1/100视口高度</li></ul><p>但vw和vh在手机竖屏和横屏的情况下值会翻转,可能会导致预期之外的效果 可以使用vmin和vmax</p><p>vmin和vmax是与当下屏幕的宽度和高度的最大值或最小值有关 取决于哪个更大和更小</p>`,120)]))}const p=a(t,[["render",d]]),h=JSON.parse('{"path":"/front/css/10/","title":"10 移动端开发","lang":"zh-CN","frontmatter":{"title":"10 移动端开发","createTime":"2025/06/18 21:06:26","permalink":"/front/css/10/"},"readingTime":{"minutes":11.57,"words":3470},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/CSS/10 移动端开发.md","headers":[]}');export{p as comp,h as data};
